INSERT INTO `events` VALUES (1,'Discovering the new Laravel Forge platform 🚀','2025-10-04 11:00:00','En Ligne','Rejoignez-nous pour une session exclusive dédiée à la nouvelle génération de Laravel Forge.\nNous allons explorer ensemble les nouvelles fonctionnalités, les améliorations majeures et la nouvelle expérience utilisateur qui font de Forge un outil incontournable pour le déploiement et la gestion d’applications Laravel.','https://calendar.app.google/CajNAMdpKjN9A7fi8','https://calendar.app.google/CajNAMdpKjN9A7fi8',1,'2025-10-03 00:46:15','2025-10-03 00:52:52'),(2,'Senegal PHP and Laravel Event','2025-11-01 09:00:00','Orange Digital Center','​🎉 PHP & Laravel Sénégal – Premier Événement Communautaire\n\n​Rejoins-nous le 1er novembre 2025 pour le tout premier événement PHP & Laravel Sénégal organisé par la communauté Laravel Sénégal !\nAu programme : des talks techniques et inspirants, des échanges entre développeurs, et une ambiance conviviale autour du framework Laravel et de l’écosystème PHP.','https://luma.com/o6zd6mr8','https://luma.com/o6zd6mr8',1,'2025-10-21 14:36:24','2025-10-21 14:36:24'),(3,'Models and Eloquent','2025-11-22 11:00:00','google meet','Hello la communauté Laravel Senegal 👋,\nNous sommes ravis de vous annoncer que notre prochain meetup aura lieu demain Samedi 22 novembre sur Google meet ! 🎉\n\nPour cette session, nous aurons l’honneur d’accueillir Lionnel, un développeur passionné par Laravel et très actif dans l’écosystème. Il viendra nous partager ses connaissances sur un sujet essentiel : les modèles (Models) en Laravel.',NULL,NULL,1,'2025-11-24 07:46:42','2025-11-24 07:46:42'),(4,'Partage d\'Experience Et Opportinutés de Carrière','2025-11-29 11:00:00','google meet','🎉 Meetup Laravel Senegal – 29 Novembre 2025\nThème : Partage d’Expérience & Orientation de Carrière\n\nInvité : Ousmane Ndiaye — Chef du Département Infrastructure & Territorialité à l’ARTP, Développeur Laravel depuis la version 3\n\nRejoignez-nous pour un meetup exceptionnel où nous aurons l’honneur d’accueillir Ousmane Ndiaye, une figure reconnue dans l’écosystème technologique sénégalais. Avec plus d’une décennie d’expérience, Ousmane a vu Laravel évoluer depuis sa version 3 et partagera avec nous un retour d’expérience unique, riche en conseils et en perspectives.','https://calendar.app.google/uox221k6U2d5eT6TA','https://calendar.app.google/uox221k6U2d5eT6TA',1,'2025-11-28 14:22:24','2025-11-28 14:22:24'),(5,'Laravel Senegal Online meetup','2025-12-06 11:15:00','Google meet','🚀 Next Laravel Senegal online meetup!\nWe’re happy to welcome Wendell Adriel, Solutions Architect at TrackStreet, for a special session with the community.\nTopic: Learn how REST APIs shape modern apps\n📅 Saturday, 06 December 2025\n⏰ 11:15 AM GMT\n📍 Live on Google Meet','https://calendar.app.google/AwimmUMaZDkNWLXt5','https://calendar.app.google/AwimmUMaZDkNWLXt5',1,'2025-12-03 15:51:48','2025-12-03 15:51:48'),(6,'Implémentation d’une architecture microservices avec larave','2026-01-24 11:00:00','Jitsi Meet','Nous avons le plaisir de vous informer de notre premier événement de l’année 2026 en collaboration avec la communauté Laravel Côte D\'Ivoire (CI) \nDate : samedi 24 Janvier 2026 à partir de 11h \nSujet : implémentation d’une architecture microservices avec larave . \nGuest : Pape Hamady FALL ','https://lnkd.in/evr2jtbC','https://lnkd.in/evr2jtbC',1,'2026-03-23 06:27:26','2026-03-23 06:33:39'),(7,'Multi-Agent AI Development in Laravel: Planning, Execution & QA with Claude','2026-02-07 00:00:00','Jitsi Meet','Tomorrow, February 7, we’re excited to host our second meetup, in collaboration with Laravel Côte D\'Ivoire (CI) \n🎤 Guest speaker: Percy M. \n💡 Talk: Multi-Agent AI Development in Laravel: Planning, Execution & QA with Claude. ','https://luma.com/301dxx9a','https://luma.com/301dxx9a',1,'2026-03-23 06:30:06','2026-03-23 06:30:06'),(8,'Du Controller Spaghetti à un laravel propre et lisible','2026-02-28 11:00:00','Jitsi Meet','MEETUP LARAVEL Francophone \n📅 Samedi 28 Février 2026 à 11h00\nLien d\'inscription: https://luma.com/pzj6hb6q\n\nNous avons l\'honneur d\'accueillir un invité d\'exception pour ce meetup :\n👨‍💻 Thibault Chazottes\n🎓 Formateur web sur Udemy\n⚡ Développeur Sénior Laravel & Vue.js\n💡 Il accompagne les startups, PME et entrepreneurs dans la création de leurs outils digitaux sur-mesure : SaaS, ERP, CRM...\n\n🎁 Bonus exclusif pour la communauté :\nThibault Chazottes propose la formation \"Maîtrisez Laravel\" la plus complète de 2026 !\n🔥 En vous inscrivant via le formulaire ci-dessous, vous bénéficierez d\'un code promo au prix le plus bas disponible sur Udemy !\n👉 S\'inscrire : https://tally.so/r/aQ6KXb\n\nPartagez autour de vous ! Tous les niveaux sont les bienvenus 🙌','https://luma.com/pzj6hb6q','https://luma.com/pzj6hb6q',1,'2026-03-23 06:33:09','2026-03-23 06:33:09');
