INSERT INTO `projects` VALUES (1,'laravel-senegal-website',7,'Laravel Senegal Website','Le site de la communauté Laravel Sénégal est une plateforme dédiée aux développeurs passionnés par Laravel et PHP au Sénégal et en Afrique francophone.','https://github.com/Laravel-SN-Community/laravel.sn','https://laravel-senegal.com','approved','2025-10-29 22:47:35','2025-10-29 22:47:35'),(2,'garap-app',6,'Garap app','Garap est une plateforme publique qui aide les patients à mieux accéder à l’information sur leurs médicaments.\nGrâce à Garap, les utilisateurs peuvent :\n\n1. Consulter facilement le prix public de leurs médicaments.\n2. Comprendre la posologie, les indications et les effets secondaires de leurs traitements grâce à l’intelligence artificielle.\n3. Trouver rapidement les pharmacies les plus proches qui acceptent leur IPM (Institution de Prévoyance Maladie).',NULL,'https://sagarap.com/','approved','2025-10-30 18:11:25','2025-10-30 18:11:25'),(3,'laraswagger',33,'Laraswagger','laraswagger est un package Laravel conçu pour automatiser la génération de documentation Swagger. Une fois installé, il ne nécessite aucune configuration supplémentaire. Ce package garantit que votre documentation API reste toujours à jour avec un minimum d\'effort.','https://github.com/bamagid/Laraswager','https://github.com/bamagid/Laraswager','approved','2025-11-04 10:00:54','2025-11-04 10:00:54'),(4,'aida-gateway',18,'Aida Gateway','Package Laravel pour intégrer facilement les paiements Mobile Money au Sénégal (Orange Money, Wave, Free Money, E-money) avec une API unifiée, webhooks automatiques et gestion complète des transactions.','https://github.com/weexduunx/AidaGateway.git','https://packagist.org/packages/weexduunx/laravel-aida-gateway','approved','2025-11-05 23:30:33','2025-11-05 23:30:33'),(5,'sdbsn',40,'SDBSN','Ce projet est une application web complète, conçue avec Python, HTML, CSS, JS et Firebase, qui centralise les ressources pédagogiques de trois années de licence. Elle sert de bibliothèque numérique pour les étudiants, avec des cours, des tutos et des documents d\'accompagnement.',NULL,'https://sdbsn-codes.netlify.app/','approved','2025-11-09 00:39:47','2025-11-09 00:39:47'),(6,'8fef595c-4633-4f84-8615-67276ab8e544',44,'WebStage','WebStage est une solution moderne et intuitive pour gérer les présences, analyser les données et améliorer la productivité. Développée avec les dernières technologies (Laravel, Vue.js, Inertia.js Tailwind CSS et Chart.js), elle offre une expérience utilisateur fluide et des fonctionnalités puissantes.','https://github.com/rosto-infinity/v-webstage','https://stage.devinsto.com/','approved','2025-11-15 16:14:47','2025-11-15 16:14:47'),(7,'005ee430-c620-45d2-87f1-8ff7ff69bf79',44,'Devinsto.com','Devinsto\nApprenez, Créez, Collaborez sans limites.\nTransformez votre passion en compétences pratiques. La plateforme ultime pour maîtriser le développement web, le design et bien plus encore.',NULL,'https://devinsto.com/','approved','2025-11-15 16:19:37','2025-11-15 16:19:37'),(8,'33f4f5a6-e40e-4098-9513-cc2a2edb3d7a',44,'EventStyleEntertainment','**Spécialiste** des événements artistiques, culturels et corporatifs au Cameroun, nous offrons des prestations sur mesure grâce à un réseau de services et de prestataires de qualité. **Organisateurs du Salon de l\'Événementiel Corporatif du Cameroun**, nous transformons chaque projet en une expérience mémorable.\n![](https://laravel-senegal.com/storage/9mM9ggtyHikJt36P0DO0myCNlBbfYLtnISegCSH3.jpg)',NULL,'https://eventstylentertainment.com/','approved','2025-11-17 17:06:49','2025-11-17 17:06:49'),(9,'e75461dd-e4b7-4e14-bd0f-b62ac2e723b7',44,'Projet Laravel : Gestion des Partenaires','Ce projet est une application web développée avec le framework Laravel. Il permet de gérer des partenaires, avec des fonctionnalités pour les utilisateurs authentifiés et les administrateurs. L\'application inclut également un système de gestion des profils et des partenaires approuvés.','https://github.com/rosto-infinity/laravel.cfpcanadienne.com','https://laravel.cfpcanadienne.com/','approved','2025-11-20 11:39:33','2025-11-20 11:39:33');
/*!40000 ALTER TABLE `projects` ENABLE KEYS */;
UNLOCK TABLES;

